func readEmbeddedAssetContent(key string) ([]byte, error) {
	contentBase64, ok := embeddedAssetContentBase64ByKey[key]
	if !ok {
		return nil, fmt.Errorf("unknown GFM asset: %s", key)
	}

	content, err := base64.StdEncoding.DecodeString(contentBase64)
	if err != nil {
		return nil, fmt.Errorf("decode embedded GFM asset %s: %w", key, err)
	}
	return content, nil
}
